const { changeScope, riskDomain, has_security_surface, has_test_changes, has_api_changes, reasoning } = result;
const taskText = triggeringMessage.content?.text || '';
if (!taskText || !taskText.trim()) throw new Error('ISSUE_OPENED has no text content — nothing to review');

if (changeScope === 'UNCERTAIN' || riskDomain === 'UNCERTAIN') {
  return {
    topic: 'CONDUCTOR_ESCALATE',
    content: {
      text: reasoning,
      data: { changeScope, riskDomain, has_security_surface, has_test_changes, has_api_changes, reasoning, taskText }
    }
  };
}

const getTier = () => {
  if (changeScope === 'CROSS_CUTTING') return 'candle';
  if (changeScope === 'MODULE' && riskDomain === 'SENSITIVE') return 'candle';
  if (changeScope === 'MODULE' || riskDomain === 'SENSITIVE') return 'book';
  return 'bell';
};

const tier = getTier();
const tierParams = {
  bell:   { analyst_level: 'level2', validator_count: 1, max_iterations: 3, max_tokens: 100000 },
  book:   { analyst_level: 'level2', validator_count: 2, max_iterations: 4, max_tokens: 150000 },
  candle: { analyst_level: 'level3', validator_count: 2, max_iterations: 5, max_tokens: 150000 }
};

const config = {
  base: 'code-review-workflow',
  params: {
    tier,
    ...tierParams[tier],
    validator_level: 'level2',
    change_scope: changeScope,
    risk_domain: riskDomain,
    has_security_surface: !!has_security_surface,
    has_test_changes: !!has_test_changes,
    has_api_changes: !!has_api_changes
  }
};

return {
  topic: 'CLUSTER_OPERATIONS',
  content: {
    text: `[CODE-REVIEW:${tier.toUpperCase()}] ${reasoning}`,
    data: {
      operations: [
        { action: 'load_config', config },
        { action: 'publish', topic: 'ISSUE_OPENED', content: { text: taskText }, metadata: { _republished: true } }
      ]
    }
  }
};

const { changeScope, riskDomain, has_security_surface, has_test_changes, has_api_changes, reasoning } = result;

let taskText = triggeringMessage.content?.data?.taskText || '';
if (!taskText) {
  taskText = triggeringMessage.content?.text || '';
}
if (!taskText) {
  const publishOp = triggeringMessage.content?.data?.operations?.find(op => op.action === 'publish');
  taskText = publishOp?.content?.text || '';
}

const getTier = () => {
  if (changeScope === 'CROSS_CUTTING') return 'candle';
  if (changeScope === 'MODULE' && riskDomain === 'SENSITIVE') return 'candle';
  if (changeScope === 'MODULE' || riskDomain === 'SENSITIVE') return 'book';
  return 'bell';
};

const tier = getTier();
const tierParams = {
  bell:   { analyst_level: 'level2', validator_count: 1, max_iterations: 3, max_tokens: 100000 },
  book:   { analyst_level: 'level2', validator_count: 2, max_iterations: 4, max_tokens: 150000 },
  candle: { analyst_level: 'level3', validator_count: 2, max_iterations: 5, max_tokens: 150000 }
};

const config = {
  base: 'code-review-workflow',
  params: {
    tier,
    ...tierParams[tier],
    validator_level: 'level2',
    change_scope: changeScope,
    risk_domain: riskDomain,
    has_security_surface: !!has_security_surface,
    has_test_changes: !!has_test_changes,
    has_api_changes: !!has_api_changes
  }
};

return {
  topic: 'CLUSTER_OPERATIONS',
  content: {
    text: `Senior: [CODE-REVIEW:${tier.toUpperCase()}] ${reasoning}`,
    data: {
      operations: [
        { action: 'load_config', config },
        { action: 'publish', topic: 'ISSUE_OPENED', content: { text: taskText }, metadata: { _republished: true } }
      ]
    }
  }
};
